def sort_users(users, field):
    return sorted(users, key=lambda u: u[field])

users = [
    {'name': 'carol', 'created_at': '2024-03-01'},
    {'name': 'alice', 'created_at': '2024-01-15'},
    {'name': 'bob', 'created_at': '2024-02-10'},
]
print(sort_users(users, 'name'))
print(sort_users(users, 'created_at'))

