def rank_users(users):
    return sorted(users, key=lambda u: (u['role'] != 'admin', -u['score']))

users = [
    {'name': 'alice', 'role': 'member', 'score': 90},
    {'name': 'bob', 'role': 'admin', 'score': 75},
    {'name': 'carol', 'role': 'admin', 'score': 88},
    {'name': 'dan', 'role': 'member', 'score': 60},
]
for u in rank_users(users):
    print(u['role'], u['score'], u['name'])
